(function () {
"use strict";

/* =========================================
   AKSHAT NETWORK TRUST SYSTEM
========================================= */

/*
   TRUSTED FULL WEBSITE PREFIXES
   Any page under these domains is trusted
*/
var TRUSTED_PREFIXES = [

	"https://akshat-881236.github.io/",
	"https://akshat-145609.github.io/",
	"https://itsakshatnetworkhub-881238.github.io/",

	/* DPG Notes and ANH Dashboard FULL WEBSITE */
	"https://dpgnotes.web.app/",
	"https://anh-dashboard-881238.web.app/",
	"https://anh-dashboard-881238.web.app/admin.html"
];

/*
   TRUSTED EXACT URLS
   Only single pages should go here
*/
var TRUSTED_EXACT_URLS = [

	/*
	   Example:
	   "https://example.com/special-page.html"
	*/
];

/* =========================================
   CONFIG
========================================= */

var GOOD_DURATION = 3000;
var BAD_DURATION  = 4000;

var ENABLE_REDIRECT = false;

var SAFE_REDIRECT =
	"https://akshat-881236.github.io/AkshatNetworkHub/";

/* =========================================
   MESSAGE DATABASE
========================================= */

var GOOD_MESSAGES = [

	"Welcome to Akshat Project Network",
	"Official Akshat Network page loaded",
	"Verified project environment",
	"Secure network detected",
	"Trusted repository accessed",
	"Akshat Network integrity confirmed",
	"Authorized ANH ecosystem detected",
	"TrackerJS security validation passed"
];

var BAD_MESSAGES = [

	"You are outside Akshat Project Network",
	"Unverified website detected",
	"This page is not under Akshat control",
	"External domain loaded",
	"Proceed with caution",
	"Security notice: outside network",
	"TrackerJS blocked this webpage",
	"Unsafe or untrusted environment detected"
];

/* =========================================
   UTIL
========================================= */

function pick(arr) {

	return arr[
		Math.floor(Math.random() * arr.length)
	];
}

/* =========================================
   URL NORMALIZER
========================================= */

function normalizeURL(url) {

	try {

		/*
		   Remove hash
		*/
		url = url.split("#")[0];

		/*
		   Remove trailing slash duplicates
		*/
		return url.replace(/\/+$/, "/");

	} catch {

		return url;
	}
}

/* =========================================
   TRUST VALIDATION
========================================= */

function isTrusted(url) {

	url = normalizeURL(url);

	/* PREFIX CHECK */
	for (var i = 0; i < TRUSTED_PREFIXES.length; i++) {

		var trustedPrefix =
			normalizeURL(TRUSTED_PREFIXES[i]);

		if (url.indexOf(trustedPrefix) === 0) {

			return true;
		}
	}

	/* EXACT PAGE CHECK */
	for (var j = 0; j < TRUSTED_EXACT_URLS.length; j++) {

		var exact =
			normalizeURL(TRUSTED_EXACT_URLS[j]);

		if (url === exact) {

			return true;
		}
	}

	return false;
}

/* =========================================
   BANNER UI
========================================= */

function showBanner(text, bg, duration) {

	var wrapper = document.createElement("div");

	wrapper.innerHTML = `

	<style>

		#ak-banner{

			position:fixed;
			top:0;
			left:0;
			right:0;

			z-index:999999;

			padding:14px;

			text-align:center;

			font-family:system-ui,Arial;
			font-size:14px;
			font-weight:600;

			color:#fff;

			background:${bg};

			box-shadow:0 2px 10px rgba(0,0,0,.3);

			animation:slideDown .35s ease;
		}

		@keyframes slideDown{

			from{
				transform:translateY(-100%);
			}

			to{
				transform:translateY(0);
			}
		}

	</style>

	<div id="ak-banner">

		${text}

	</div>
	`;

	document.body.appendChild(wrapper);

	setTimeout(function () {

		if (wrapper.parentNode) {

			wrapper.remove();
		}

	}, duration);
}

/* =========================================
   BLOCK PAGE
========================================= */

function blockPage() {

	document.body.innerHTML = "";

	document.documentElement.style.overflow =
		"hidden";

	document.body.style.overflow = "hidden";

	var overlay = document.createElement("div");

	overlay.innerHTML = `

	<style>

		#ak-block-screen{

			position:fixed;
			inset:0;

			background:#111;
			color:#fff;

			z-index:999999999;

			display:flex;
			align-items:center;
			justify-content:center;

			text-align:center;

			padding:30px;

			font-family:system-ui,Arial;
		}

		#ak-block-box{

			max-width:650px;
		}

		#ak-block-box h1{

			font-size:32px;

			margin-bottom:15px;

			color:#ff4d4f;
		}

		#ak-block-box p{

			font-size:16px;

			line-height:1.7;

			opacity:.92;
		}

		#ak-block-box a{

			display:inline-block;

			margin-top:25px;

			padding:12px 20px;

			background:#1e8e3e;

			color:#fff;

			text-decoration:none;

			border-radius:8px;

			font-weight:600;
		}

	</style>

	<div id="ak-block-screen">

		<div id="ak-block-box">

			<h1>

				Access Blocked

			</h1>

			<p>

				This webpage is not part of the
				official Akshat Network ecosystem.

				<br><br>

				TrackerJS security policy blocked
				page access to protect users from
				untrusted or external environments.

			</p>

			<a href="${SAFE_REDIRECT}">

				Go To Official Network

			</a>

		</div>

	</div>
	`;

	document.body.appendChild(overlay);

	if (ENABLE_REDIRECT) {

		setTimeout(function () {

			window.location.href =
				SAFE_REDIRECT;

		}, 2500);
	}
}

/* =========================================
   MAIN
========================================= */

document.addEventListener(
	"DOMContentLoaded",
	function () {

		var currentURL =
			window.location.href;

		var trusted =
			isTrusted(currentURL);

		/* TRUSTED */
		if (trusted) {

			showBanner(
				pick(GOOD_MESSAGES),
				"#1e8e3e",
				GOOD_DURATION
			);
		}

		/* UNTRUSTED */
		else {

			showBanner(
				pick(BAD_MESSAGES),
				"#d93025",
				BAD_DURATION
			);

			setTimeout(function () {

				blockPage();

			}, BAD_DURATION);
		}
	}
);

})();
